const body = $input.first().json.body || $input.first().json;

const required = ["actorId", "targetId", "resourceType", "action", "allowed"];
const missing = required.filter(f => body[f] === undefined);

if (missing.length > 0) {
  return [{ json: { error: true, message: "Missing fields: " + missing.join(", "), statusCode: 400 } }];
}

const entry = {
  timestamp: new Date().toISOString(),
  actorId: body.actorId,
  targetId: body.targetId,
  resourceType: body.resourceType,
  action: body.action,
  allowed: body.allowed,
  reason: body.reason || "none",
  neverClauseViolation: body.neverClauseViolation || false,
  severity: (!body.allowed && body.neverClauseViolation) ? "CRITICAL" : (!body.allowed ? "WARNING" : "INFO"),
  auditId: "NCP-" + Date.now() + "-" + Math.random().toString(36).substr(2, 6)
};

return [{ json: entry }];

const entry = $input.first().json;
console.log("[CRITICAL NCP VIOLATION] Never Clause breached!");
console.log("Actor: " + entry.actorId + " -> Target: " + entry.targetId);
console.log("Action: " + entry.action + " on " + entry.resourceType);
console.log("Reason: " + entry.reason);
console.log("Audit ID: " + entry.auditId);
// Future: Send to Slack #ncp-violations channel
// Future: Write to D1 agent-memory database
return [{ json: { ...entry, logged: true, alertSent: false, channel: "#ncp-violations (pending Slack integration)" } }];

const entry = $input.first().json;
console.log("[NCP AUDIT] " + entry.severity + " | " + entry.actorId + " -> " + entry.targetId + " | " + entry.action + " | allowed=" + entry.allowed);
// Future: Batch write to D1 aquarium-archive database
return [{ json: { ...entry, logged: true } }];
